export default function Menu() {
  return (
    <div className="flex bg-red-200 w-full h-32 align-center">
      <a
        className="inline-flex text-4xl font-sans font-bold bg-yellow-300 h-fit"
        href="#"
      >
        Corrida dos DEVs{" "}
        <img src="logo.svg" alt="Corrida-dos-devs-logo" className="h-10" />
      </a>
      <ul className="bg-blue-900 inline-flex text-right h-fit w-1/3 justify-evenly">
        <li className="text-2xl">Ranking</li>
        <li className="text-2xl">Registro</li>
        <li className="text-2xl bg-green-900 text-white w-32 t">Login</li>
      </ul>
    </div>
  );
}
